//------------------------------------------------------------------------------
// bin2gray.sv
// published as part of https://github.com/pConst/basic_verilog
// Konstantin Pavlov, pavlovconst@gmail.com
//------------------------------------------------------------------------------

// INFO ------------------------------------------------------------------------
//  Gray code to binary converter
//  Combinational design


/* --- INSTANTIATION TEMPLATE BEGIN ---

bin2gray #(
  .WIDTH( 32 )
) BG1 (
  .bin_in(  ),
  .gray_out(  )
);

--- INSTANTIATION TEMPLATE END ---*/

module bin2gray #( parameter
  WIDTH = 32
)(
  input [WIDTH-1:0] bin_in,
  output logic[WIDTH-1:0] gray_out
);

  always_comb begin
    gray_out[WIDTH-1:0] = bin_in[WIDTH-1:0] ^ ( bin_in[WIDTH-1:0] >> 1 );
  end

endmodule

//------------------------------------------------------------------------------
// gray2bin.sv
// published as part of https://github.com/pConst/basic_verilog
// Konstantin Pavlov, pavlovconst@gmail.com
//------------------------------------------------------------------------------

// INFO ------------------------------------------------------------------------
//  Binary to gray code converter
//  Combinational design


/* --- INSTANTIATION TEMPLATE BEGIN ---

gray2bin #(
  .WIDTH( 32 )
) GB1 (
  .gray_in(  ),
  .bin_out(  )
);

--- INSTANTIATION TEMPLATE END ---*/

module gray2bin #( parameter
   WIDTH = 32
)(
   input [WIDTH-1:0] gray_in,
   output logic [WIDTH-1:0] bin_out
);

   always_comb begin
      bin_out[WIDTH-1:0] = '0;

      for( integer i=0; i<WIDTH; i++ ) begin
         bin_out[WIDTH-1:0] ^= gray_in[WIDTH-1:0] >> i;
      end
   end

endmodule

//------------------------------------------------------------------------------
// bin2pos.sv
// Konstantin Pavlov, pavlovconst@gmail.com
//------------------------------------------------------------------------------

// INFO ------------------------------------------------------------------------
//  Converts binary coded value to positional code (one-hot in specified position)
//  Thus 2'd0 becomes 4'b0001 and 8'd5 becomes 256'b100000
//  Module is being synthesized into combinational logic only
//  See also pos2bin.sv module for inverse transformation


/* --- INSTANTIATION TEMPLATE BEGIN ---

bin2pos #(
  .BIN_WIDTH( 8 )
) BP1 (
  .bin(  ),
  .pos(  )
);

--- INSTANTIATION TEMPLATE END ---*/


module bin2pos #( parameter
  BIN_WIDTH = 8,
  POS_WIDTH = 2**BIN_WIDTH
)(
  input [(BIN_WIDTH-1):0] bin,
  output logic [(POS_WIDTH-1):0] pos
);


always_comb begin
  pos = 0;
  pos[bin] = 1'b1;
end

endmodule

//------------------------------------------------------------------------------
// pos2bin.sv
// Konstantin Pavlov, pavlovconst@gmail.com
//------------------------------------------------------------------------------

// INFO ------------------------------------------------------------------------
//  Converts positional (one-hot) value to binary representation
//  Thus 4'b0001 becomes 2'd0 and 256'b10100000 becomes 8'd5
//  Module is being synthesized into combinational logic only
//  See also bin2pos.sv module for inverse transformation


/* --- INSTANTIATION TEMPLATE BEGIN ---

pos2bin #(
  .BIN_WIDTH( 8 )
) PB1 (
  .pos(  ),
  .bin(  ),

  .err_no_hot(  ),
  .err_multi_hot(  )
);

--- INSTANTIATION TEMPLATE END ---*/


module pos2bin #( parameter
  BIN_WIDTH = 8,
  POS_WIDTH = 2**BIN_WIDTH
)(
  input [(POS_WIDTH-1):0] pos,
  output logic [(BIN_WIDTH-1):0] bin,

// error flags
  output logic err_no_hot,    // no active bits in pos[] vector
  output logic err_multi_hot  // multiple active bits in pos[] vector
                              // only least-sensitive active bit affects the output
);


assign err_no_hot = (pos[(POS_WIDTH-1):0] == 0);

integer i;

logic found_hot;
always_comb begin
  err_multi_hot = 0;
  bin[(BIN_WIDTH-1):0] = 0;
  found_hot = 0;
  for (i=0; i<POS_WIDTH; i++) begin

    if ( ~found_hot && pos[i] ) begin
      bin[(BIN_WIDTH-1):0] = i[(BIN_WIDTH-1):0];
    end

    if ( found_hot && pos[i] ) begin
      err_multi_hot=1'b1;
    end

    if ( pos[i] ) begin
      found_hot = 1'b1;
    end

  end // for
end // always_comb

endmodule

//------------------------------------------------------------------------------
// leave_one_hot.v
// Konstantin Pavlov, pavlovconst@gmail.com
//------------------------------------------------------------------------------

// INFO -------------------------------------------------------------------------
// Completely combinational module that leaves only lowest hot bit
// compared to input vector
//
// For example 16'b1101_0000 becomes 8'b0001_0000
//             16'b1101_0010 becomes 8'b0000_0010


/* --- INSTANTIATION TEMPLATE BEGIN ---

leave_one_hot #(
  .WIDTH( 32 )
) OH1 (
  .in(  ),
  .out(  )
);

--- INSTANTIATION TEMPLATE END ---*/


module leave_one_hot #( parameter
  WIDTH = 32
)(
  input [WIDTH-1:0] in,
  output logic [WIDTH-1:0] out
);


genvar i;
generate
  for( i=1; i<WIDTH; i++ ) begin : gen_for

    always_comb begin
        out[i] <= in[i] && ~( |in[(i-1):0] );
    end

  end  // for i
endgenerate

assign out[0] = in[0];

endmodule

//------------------------------------------------------------------------------
// reverse_vector.sv
// Konstantin Pavlov, pavlovconst@gmail.com
//------------------------------------------------------------------------------

// INFO ------------------------------------------------------------------------
//  "Physically" reverses signal order within multi-bit bus
//  Thus in[7] signal becomes out[0], in[6] becomes out[1] and vise-versa
//  Module is no doubt synthesizable, but its instance does NOT occupy any FPGA resources!


/* --- INSTANTIATION TEMPLATE BEGIN ---

reverse_vector #(
  .WIDTH( 8 )         // WIDTH must be >=2
) RV1 (
  .in( smth[7:0] ),
  .out( htms[7:0] )   // reversed bit order
);

--- INSTANTIATION TEMPLATE END ---*/


module reverse_vector #( parameter
  WIDTH = 8
)(
  input [(WIDTH-1):0] in,
  output logic [(WIDTH-1):0] out
);

  integer i;
  always_comb begin
    for (i = 0; i < WIDTH ; i++) begin : gen_reverse
      out[i] = in[(WIDTH-1)-i];
    end // for
  end // always_comb

endmodule

//------------------------------------------------------------------------------
// reverse_dimensions.sv
// Konstantin Pavlov, pavlovconst@gmail.com
//------------------------------------------------------------------------------

// INFO ------------------------------------------------------------------------
//  "Physically" reverses dimension order in systemv_erilog 2D vector
//  Thus in[7][1] signal becomes out[1][7], in[6][10] becomes out[10][6] and vise-versa
//  Module is no doubt synthesizable, but its instance does NOT occupy any FPGA resources!


/* --- INSTANTIATION TEMPLATE BEGIN ---

reverse_dimensions #(
  .D1_WIDTH( 8 ),
  .D2_WIDTH( 3 )
) RD1 (
  .in( smth[7:0][2:0] ),
  .out( htms[2:0][7:0] )   // reversed bit order
);

--- INSTANTIATION TEMPLATE END ---*/


module reverse_dimensions #( parameter
  D1_WIDTH = 8,        // first dimention width
  D2_WIDTH = 3         // second dimention width
)(
  input [D1_WIDTH-1:0][D2_WIDTH-1:0] in,
  output logic [D2_WIDTH-1:0][D1_WIDTH-1:0] out
);


genvar i;
genvar j;
generate
  for (i = 0; i < D1_WIDTH ; i++) begin : gen_i
  for (j = 0; j < D2_WIDTH ; j++) begin : gen_j

    always_comb begin
      out[j][i] = in[i][j];
    end // always_comb

  end // for
  end // for
endgenerate

endmodule

